// ─── CLICK SOUND (embedded) ──────────────────────────────────────────────────
const CLICK_SOUND_B64 = "data:audio/mp3;base64,";

function playClick() {
  try {
    const audio = new Audio(CLICK_SOUND_B64);
    audio.volume = 0.55;
    audio.play().catch(() => {});
  } catch (_) {}
}


