// ─── COMPONENT ───────────────────────────────────────────────────────────────
export default function Profilesetup() {
  const navigate = useNavigate();
  const [user,    setUser]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving,  setSaving]  = useState(false);
  const [step,    setStep]    = useState(1);
  const totalSteps = 4;

  const [xp,        setXp]       = useState(0);
  const [earnedIds, setEarnedIds] = useState([]);
  const [toast,     setToast]    = useState(null);
  const [toastKey,  setToastKey] = useState(0);

  const totalXp = STEPS.reduce((s, st) => s + st.xp, 0);

  const [form, setForm] = useState({
    fullName:"", gender:"", country:"", educationLevel:"",
    course:"", college:"", domain:"", role:"", experience:"", bio:"", linkedin:""
  });

  // ── auth check ──
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (u) => {
      if (!u) { navigate("/login"); return; }
      setUser(u);
      try {
        const snap = await getDoc(doc(db, "users", u.uid));
        if (snap.exists() && snap.data().isProfileComplete) {
          navigate("/newdashboard"); return;
        }
      } catch (err) { console.error(err); }
      setLoading(false);
    });
    return () => unsub();
  }, [navigate]);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const showToast = (msg) => {
    setToast(msg);
    setToastKey(k => k + 1);
    setTimeout(() => setToast(null), 2400);
  };

  const awardStep = (completedStep) => {
    const st = STEPS.find(s => s.id === completedStep);
    if (!st) return;
    setXp(prev => prev + st.xp);
    const ach = ACHIEVEMENTS.find(a => a.step === completedStep);
    if (ach && !earnedIds.includes(ach.id
      
    )) {
      setEarnedIds(prev => [...prev, ach.id]);
      // showToast(`${ach.emoji} ${ach.label} unlocked! +${st.xp} XP`);
    } else {
      // showToast(`XP earned!`);
    }
  };

  const handleNext = () => {
    playClick();
    awardStep(step);
    setStep(s => s + 1);
  };

  const isValid = () =>
    form.fullName && form.gender && form.country &&
    form.educationLevel && form.course && form.college &&
    form.domain && form.role && form.experience;

  const handleSubmit = async () => {
    if (!user || saving) return;
    if (!isValid()) { alert("Please fill all required fields"); return; }
    try {
      setSaving(true);
      playClick();
      awardStep(4);
      await setDoc(doc(db, "users", user.uid), {
        ...form, email: user.email,
        isProfileComplete: true, createdAt: new Date()
      });
      setTimeout(() => navigate("/newdashboard"), 800);
    } catch (err) {
      console.error(err); alert("Failed to save profile");
    } finally { setSaving(false); }
  };

  if (loading) {
    return (
      <>
        <style>{styles}</style>
        <div className="ps-loading"><div className="ps-spin"/><span>Loading your profile…</span></div>
      </>
    );
  }

  const curStep = STEPS[step - 1];
  const xpPct = Math.min(100, (xp / totalXp) * 100);

  return (
    <>
      <style>{styles}</style>
      {toast && (
        <div key={toastKey} className="ps-toast">
          <span className="ps-toast-pill">XP</span>
          {toast}
        </div>
      )}

      <div className="ps-root">
        <div className="ps-layout">

          {/* brand bar */}
          <div className="ps-brand">
            <span className="ps-brand-name">Student Collaboration Hub</span>
            <span className="ps-brand-step">Step {step} of {totalSteps}</span>
          </div>

          {/* progress rail */}
          <div className="ps-rail">
            {STEPS.map(s => (
              <div key={s.id}
                className={`ps-rail-seg${s.id < step ? " done" : s.id === step ? " active" : ""}`}
              />
            ))}
          </div>

          {/* XP strip */}
          <div className="ps-xp-strip">
            <div className="ps-xp-icon">⚡</div>
            <div className="ps-xp-info">
              <div className="ps-xp-label">Builder XP · Level {Math.floor(xp / 150) + 1}</div>
              <div className="ps-xp-track">
                <div className="ps-xp-fill" style={{ width: `${xpPct}%` }} />
              </div>
            </div>
            <div className="ps-xp-num">{xp} / {totalXp}</div>
          </div>

          {/* achievement badges */}
          <div className="ps-badges">
            {ACHIEVEMENTS.map(a => (
              <div key={a.id} className={`ps-badge${earnedIds.includes(a.id) ? " earned" : ""}`}>
                <span>{a.emoji}</span>{a.label}
              </div>
            ))}
          </div>

          {/* main form card */}
          <div className="ps-card">
            {/* step header */}
            <div className="ps-step-header">
              <div className="ps-step-num">{curStep.emoji}</div>
              <div className="ps-step-meta">
                <div className="ps-step-kicker">Step {step} — {xp + curStep.xp} XP on completion</div>
                <div className="ps-step-title">{curStep.title}</div>
                <div className="ps-step-hint">{curStep.hint}</div>
              </div>
            </div>

            {/* form fields */}
            <div className="ps-step-body" key={step}>
              {step === 1 && (
                <>
                  <div className="ps-group">
                    <label className="ps-label">Full Name <span style={{color:"#ea580c"}}>*</span></label>
                    <input name="fullName" placeholder="Your full name"
                      className="ps-input" value={form.fullName} onChange={handleChange}/>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">Gender <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="gender" className="ps-select" value={form.gender} onChange={handleChange}>
                      <option value="">Select gender</option>
                      {GENDERS.map(g => <option key={g}>{g}</option>)}
                    </select>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">Country <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="country" className="ps-select" value={form.country} onChange={handleChange}>
                      <option value="">Select country</option>
                      {COUNTRIES.map(c => <option key={c}>{c}</option>)}
                    </select>
                  </div>
                </>
              )}

              {step === 2 && (
                <>
                  <div className="ps-group">
                    <label className="ps-label">Education Level <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="educationLevel" className="ps-select" value={form.educationLevel} onChange={handleChange}>
                      <option value="">Select level</option>
                      {EDUCATION_LEVELS.map(e => <option key={e}>{e}</option>)}
                    </select>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">Course / Degree <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="course" className="ps-select" value={form.course} onChange={handleChange}>
                      <option value="">Select course</option>
                      {COURSES.map(c => <option key={c}>{c}</option>)}
                    </select>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">College / University <span style={{color:"#ea580c"}}>*</span></label>
                    <input name="college" placeholder="e.g. IIT Bombay / MIT"
                      className="ps-input" value={form.college} onChange={handleChange}/>
                  </div>
                </>
              )}

              {step === 3 && (
                <>
                  <div className="ps-group">
                    <label className="ps-label">Primary Domain <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="domain" className="ps-select" value={form.domain} onChange={handleChange}>
                      <option value="">Select domain</option>
                      {DOMAINS.map(d => <option key={d}>{d}</option>)}
                    </select>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">Current Role <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="role" className="ps-select" value={form.role} onChange={handleChange}>
                      <option value="">Select role</option>
                      {ROLES.map(r => <option key={r}>{r}</option>)}
                    </select>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">Experience Level <span style={{color:"#ea580c"}}>*</span></label>
                    <select name="experience" className="ps-select" value={form.experience} onChange={handleChange}>
                      <option value="">Select level</option>
                      {EXPERIENCE_LEVELS.map(ex => <option key={ex}>{ex}</option>)}
                    </select>
                  </div>
                </>
              )}

              {step === 4 && (
                <>
                  <div className="ps-group">
                    <label className="ps-label">Bio <span className="ps-opt">optional</span></label>
                    <textarea name="bio"
                      placeholder="A short intro — what you build, what you're looking for…"
                      className="ps-textarea" value={form.bio} onChange={handleChange}/>
                  </div>
                  <div className="ps-group">
                    <label className="ps-label">LinkedIn URL <span className="ps-opt">optional</span></label>
                    <input name="linkedin" placeholder="https://linkedin.com/in/yourname"
                      className="ps-input" value={form.linkedin} onChange={handleChange}/>
                  </div>
                </>
              )}
            </div>

            {/* navigation */}
            <div className="ps-nav">
              {step > 1 && (
                <button className="ps-btn-back" onClick={() => setStep(s => s - 1)}>
                  ← Back
                </button>
              )}
              {step < totalSteps ? (
                <button className="ps-btn-next" onClick={handleNext}>
                  Continue — earn +{curStep.xp} XP →
                </button>
              ) : (
                <button className="ps-btn-next" onClick={handleSubmit} disabled={saving}>
                  {saving ? "Saving…" : "🏆  Complete Profile  +100 XP"}
                </button>
              )}
            </div>
          </div>

          <p className="ps-foot-note">Your information is private and only shown to matched collaborators.</p>

        </div>
      </div>
    </>
  );
}
